INSERT INTO public.tracks (key, title, desc_text, meta_text, stats, tax, display_order) VALUES ('brick', 'Brick by Byte', 'Intelligent smart city ecosystems that sense, connect, and respond to a rapidly changing world.', 'Focus: Urban Infrastructure & IoT friction.', '[85, 70, 90, 60, 75]'::jsonb, '[12, 18, 5, 22]'::jsonb, 1) ON CONFLICT (key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('brick-0', 'brick', 'Fragmented Urban Data Silos', 'City authorities fail to anticipate disasters like floods and infrastructure failures because data from IoT, weather, and citizen reports remain isolated.', 'Legacy municipal software contracts intentionally silo data to force vendor lock-in. Emergency, sanitation, and transit departments use proprietary databases lacking unified APIs.', 'Forces cities into reactive disaster management. For instance, flood warnings are delayed until physical infrastructure is breached, increasing economic damage and delaying emergency response by critical hours.', '["Data Governance", "Vendor Lock-in", "Reactive Mgmt"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('brick-1', 'brick', 'Micro-climate Heat Alleyways', 'Traditional city-wide sensors miss localized heat pockets in narrow alleyways, leading to inaccurate emergency medical responses during heatwaves.', 'Macro-level weather stations are placed in open areas (airports, parks). They fail to account for the ''canyon effect'' of concrete and glass trapping heat in dense, low-income urban grids.', 'Ambulance routing algorithms under-prioritize specific high-density neighborhoods during heatwaves, resulting in preventable hyperthermia fatalities among vulnerable populations.', '["Sensor Blindspots", "Urban Design", "Health Inequity"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('brick-2', 'brick', 'Ghost Data Storage Costs', 'Massive volumes of ''heartbeat'' data from idle infrastructure sensors create an invisible carbon footprint through server cooling and storage costs.', 'Smart city grids are programmed to log state data (''I am functioning'') every millisecond. 99% of this data is noise, yet it is transmitted and stored indefinitely on cloud servers.', 'Municipalities bleed budget on AWS/Azure storage fees for useless data, while the energy required to cool these data centers negates the carbon savings the ''smart'' grids were supposed to achieve.', '["Cloud Waste", "IoT Noise", "Carbon Footprint"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('brick-3', 'brick', 'Sensor Decay Deserts', 'Suburbs experiencing ''maintenance lag'' where failed hardware creates blind spots in traffic management, disproportionately affecting outer-city commuters.', 'Grant money funds the installation of IoT infrastructure, but municipal budgets rarely allocate funds for the ongoing maintenance and calibration of delicate sensors exposed to weather.', 'Algorithms rely on broken sensor data, causing automated traffic lights to stall grids, or worse, environmental monitors failing to report toxic runoff in neglected districts.', '["Maintenance Deficit", "Infrastructure Decay", "Civic Budgets"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('brick-4', 'brick', 'Algorithmic Redlining in Smart Policing', 'Predictive policing algorithms trained on historical arrest data endlessly direct patrols to minority neighborhoods, creating a self-fulfilling feedback loop of surveillance.', 'Machine learning models are fed decades of biased arrest records rather than actual crime rates. The models conflate ''heavily policed areas'' with ''high crime areas''.', 'Systemic erosion of trust in civic institutions. Resources are pulled away from investigating complex crimes in favor of over-policing minor infractions in targeted zip codes.', '["Algorithmic Bias", "Surveillance", "Civil Rights"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('brick-5', 'brick', 'Digital Twin Desync', 'A city''s ''digital twin'' simulation becomes dangerously inaccurate when physical utility repairs are done manually on the fly and not logged into the central database.', 'Field workers face emergencies (e.g., burst pipes) and perform ad-hoc fixes that differ from the official blueprint. The UI for updating the digital twin is often too complex for field use.', 'When automated systems or future contractors rely on the ''desynced'' digital twin, they accidentally sever power lines or drill into active water mains, causing cascading utility failures.', '["Data Desync", "Human-in-the-loop", "Utility Risk"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('brick-6', 'brick', 'Cross-Sector Policy Blindspots (The Disconnected Urban Genome)', 'Decision-makers manage cities using isolated metrics (e.g., traffic vs. water vs. crime), failing to understand how interventions in one sector cascade into unintended consequences across the entire urban ecosystem.', 'Urban data is inherently siloed by departmental jurisdiction. Planners lack a unified predictive model—a ''City DNA''—that correlates multiple datasets to reveal the interactions and long-term effects of complex policies.', 'Cities waste billions on isolated fixes that treat symptoms rather than systemic root causes. A mobility intervention might inadvertently degrade environmental health or water security, accelerating urban decay due to a lack of holistic multi-variable simulation.', '["Systems Thinking", "Policy Myopia", "Urban Planning"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.tracks (key, title, desc_text, meta_text, stats, tax, display_order) VALUES ('popcorn', 'Reclaiming Popcorn Brains', 'Technologies that empower individuals to break unhealthy digital cycles and reclaim time.', 'Focus: Attention Economy & Cognitive Health.', '[95, 80, 75, 85, 90]'::jsonb, '[5, 25, 30, 10]'::jsonb, 2) ON CONFLICT (key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('popcorn-0', 'popcorn', 'Context Switching Lag', 'The 23-minute average recovery time lost after a ''quick'' notification check, specifically impacting deep-work professions like research and coding.', 'The human brain must flush working memory to process a new stimulus (an email ping), and then painstakingly rebuild that context to return to the original complex task.', 'A structural collapse in global productivity and innovation. Knowledge workers spend up to 40% of their day purely recovering from micro-interruptions rather than producing value.', '["Productivity Drain", "Neurology", "Deep Work"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('popcorn-1', 'popcorn', 'Algorithmic Mirroring', 'The gradual loss of linguistic variety as predictive text and LLMs narrow the user''s own vocabulary through constant suggestions.', 'Autocorrect and generative AI prioritize the most statistically common phrasing. As users accept these suggestions for efficiency, their unique voice and edge-case vocabulary atrophy.', 'A homogenization of human thought and culture. We are entering an era of ''average communication'', reducing our cognitive ability to articulate complex, nuanced, or highly emotional states.', '["Linguistic Decay", "AI Homogenization", "Cognitive Atrophy"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('popcorn-2', 'popcorn', 'Phantom Vibration Habituation', 'The neurological scarring where individuals feel phone notifications even without a device present, causing constant cortisol spikes.', 'Years of variable reward conditioning (similar to slot machines) have hyper-sensitized the somatosensory cortex to anticipate the specific vibration frequency of mobile devices.', 'Chronic elevation of base stress levels. This leads to adrenal fatigue, disrupted sleep architectures, and a baseline state of hyper-vigilance that damages long-term heart health.', '["Conditioning", "Cortisol", "Sensory Illusion"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('popcorn-3', 'popcorn', 'Infinite Scroll Amnesia', 'The phenomenon where users cannot recall a single piece of content they consumed just 5 minutes ago due to rapid dopamine dripping.', 'Short-form video platforms bypass the hippocampus (memory consolidation) by providing novel stimuli every 3 seconds, keeping the brain in a perpetual state of immediate reaction.', 'Severe degradation of declarative memory capabilities in young adults. It erodes the ability to synthesize information into long-term worldviews, replacing knowledge with fleeting algorithmic moods.', '["Memory Loss", "Dopamine Drip", "Short-form Content"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('popcorn-4', 'popcorn', 'Digital Hoarding Anxiety', 'The subtle but chronic stress of accumulating thousands of unread emails, open browser tabs, and screenshot folders that users feel compelled to keep.', 'Storage has become cheap, eliminating the natural friction of ''cleaning up''. However, the psychological weight of an unorganized, infinite digital backlog remains a heavy cognitive load.', 'Creates a paralyzing ''Zeigarnik effect''—the brain remembering uncompleted tasks. This manifests as chronic, low-level anxiety and avoidance behaviors regarding digital workspaces.', '["Digital Clutter", "Cognitive Load", "Anxiety"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('popcorn-5', 'popcorn', 'Algorithmic Determinism', 'The psychological claustrophobia of losing serendipity; the creeping realization that one''s tastes and discoveries are entirely predictable.', 'Recommendation engines optimize for ''engagement'' by feeding users only what they already like, trapping them in narrowing psychographic echo chambers.', 'Destroys intellectual exploration and serendipitous discovery. It leads to extreme cultural polarization and a sense of existential dread that one is merely a predictable data point.', '["Echo Chambers", "Determinism", "Loss of Serendipity"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.tracks (key, title, desc_text, meta_text, stats, tax, display_order) VALUES ('hunger', 'Safe Sources & Zero Hunger', 'Solutions that rethink how we grow, manage, and sustain food resources.', 'Focus: Food Security & Supply Chain Logistics.', '[70, 95, 85, 75, 65]'::jsonb, '[20, 15, 10, 25]'::jsonb, 3) ON CONFLICT (key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('hunger-0', 'hunger', 'Micronutrient Soil Depletion', 'Modern yield-focused farming creates vegetables that look healthy but lack essential selenium and zinc, leading to ''hidden hunger'' in wealthy nations.', 'Industrial agriculture incentivizes crop volume and visual perfection. Decades of aggressive monocropping and synthetic NPK fertilizers have stripped the soil of trace minerals.', 'Populations consuming massive caloric surpluses are simultaneously suffering from severe clinical malnutrition, leading to immune deficiencies and developmental delays in children globally.', '["Hidden Hunger", "Soil Health", "Agri-economics"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('hunger-1', 'hunger', 'Cold Chain Breakdown Latency', 'Minor power fluctuations in rural storage units that don''t trigger alarms but accelerate spoilage of perishable vaccines and produce.', 'Current temperature sensors report absolute failures (power loss) but fail to register prolonged, subtle temperature drifts caused by aging compressors or micro-brownouts.', 'Up to 30% of global perishable food is lost in transit. In healthcare, degraded vaccines are administered to populations under the false assumption they are still viable.', '["Logistics", "Food Waste", "Sensor Accuracy"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('hunger-2', 'hunger', 'Industrial Pre-Retail Waste', 'The massive volume of edible food discarded during the processing phase (e.g., imperfectly sliced carrots) that never reaches a store shelf.', 'Retailers enforce draconian ''cosmetic standards'' on suppliers. Automated sorting machines aggressively reject produce that is misshapen or slightly off-color, despite being perfectly nutritious.', 'Millions of tons of edible food rot in processing facility landfills, generating massive methane emissions, while local food banks struggle with supply shortages.', '["Cosmetic Standards", "Supply Chain", "Methane"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('hunger-3', 'hunger', 'Aquifer Depletion Invisibility', 'Large-scale agribusinesses unknowingly draining underground fossil water reserves much faster than they can naturally recharge.', 'Groundwater extraction is largely unmetered and invisible. Without real-time subterranean telemetry, farms pump water based on immediate surface crop needs, ignoring geological limits.', 'Permanent collapse of land (subsidence) and the imminent exhaustion of aquifers that took millennia to fill, threatening multi-generational water security for entire continents.', '["Water Security", "Resource Exhaustion", "Telemetry"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('hunger-4', 'hunger', 'Monoculture Disease Susceptibility', 'Extreme genetic uniformity in staple crops making entire regional food supplies devastatingly vulnerable to a single novel pathogen.', 'Corporate seed monopolies push highly optimized, genetically identical seeds for maximum yield. This eliminates the genetic firewall provided by biodiversity.', 'A single fungal mutation (like Panama Disease in bananas) can wipe out an entire global harvest in one season, leading to sudden, catastrophic global food shortages.', '["Biodiversity", "Food Security", "Pathogens"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('hunger-5', 'hunger', 'Vertical Farming Energy Paradox', 'High-tech indoor farms claiming sustainability while actually relying on massive amounts of fossil-fuel generated electricity.', 'Replacing the sun with LEDs and natural weather with HVAC systems requires astronomical baseline energy loads. The grid supplying this energy is still overwhelmingly fossil-based.', 'These ''green'' solutions currently emit more carbon per calorie produced than traditional farming, creating a facade of sustainability while exacerbating climate change.', '["Greenwashing", "Energy Intensity", "Agri-Tech"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.tracks (key, title, desc_text, meta_text, stats, tax, display_order) VALUES ('care', 'Care Beyond Labels', 'Innovations that address often-overlooked dimensions of health and well-being.', 'Focus: Invisible Health & Social Isolation.', '[60, 85, 95, 70, 80]'::jsonb, '[15, 10, 40, 5]'::jsonb, 4) ON CONFLICT (key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('care-0', 'care', 'Diagnostic Delay for Rare Diseases', 'The ''diagnostic odyssey'' where patients spend 7+ years moving between specialists due to lack of cross-disciplinary data sharing.', 'Medical specialists operate in silos. A rheumatologist, a neurologist, and a dermatologist may all see the same patient over years but never aggregate their localized findings.', 'Patients endure years of degenerative damage and psychological trauma from misdiagnoses. The healthcare system wastes millions on redundant tests and ineffective, generalized treatments.', '["Siloed Medicine", "Data Interoperability", "Rare Diseases"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('care-1', 'care', 'Chronic Pain Measurement Bias', 'Subjective pain scales (1-10) that fail to account for cultural and neurodivergent differences in pain expression, leading to under-medication.', 'The universal 1-10 ''smiley face'' pain scale is deeply flawed. Neurodivergent individuals may mask pain heavily, while different cultures have varying stigmas around vocalizing agony.', 'Systemic medical trauma. Vulnerable demographics are routinely dismissed as ''drug-seeking'' or simply ignored, leaving them to suffer debilitating physical agony without intervention.', '["Medical Bias", "Pain Management", "Neurodiversity"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('care-2', 'care', 'Unpaid Caregiver Burnout', 'The invisible economic and health collapse of family members providing 24/7 care without institutional support or monitoring.', 'Healthcare systems discharge chronically ill or aging patients to their families to cut hospital costs. The state provides zero training, mental health support, or financial compensation to these relatives.', 'Caregivers suffer catastrophic financial ruin, severe depression, and physical collapse. This secondary health crisis forces both patient and caregiver back into the emergency system.', '["Shadow Economy", "Caregiving", "Systemic Failure"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('care-3', 'care', 'The ''Sandwich Generation'' Squeeze', 'Middle-aged adults facing simultaneous pressures of caring for aging parents and young children with zero systemic support.', 'Increased lifespans and delayed childbearing mean the timeline for eldercare and childcare now perfectly overlap during a worker''s peak earning years.', 'A massive exit of skilled (predominantly female) labor from the workforce, coupled with unprecedented rates of clinical anxiety and stress-induced autoimmune disorders.', '["Demographics", "Labor Force", "Mental Health"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('care-4', 'care', 'Stigma of Invisible Disabilities', 'The severe lack of standard workplace accommodations for debilitating but invisible conditions like endometriosis or chronic fatigue syndrome.', 'Corporate HR policies require ''proof'' of disability that often hinges on visible mobility aids. Conditions that fluctuate wildly day-to-day confuse rigid corporate accommodation frameworks.', 'Highly capable individuals are managed out of their careers. They face quiet hostility from peers who perceive them as ''lazy'', leading to severe financial instability and isolation.', '["HR Policies", "Invisible Illness", "Workplace Equity"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('care-5', 'care', 'Peri-Menopause Knowledge Gap', 'The shocking lack of mandatory medical training and clinical research regarding the decade preceding menopause.', 'Historically, medical research centered entirely on male biology. Women''s hormonal transitions were dismissed as ''hysteria'' or simply ignored in clinical literature until very recently.', 'Millions of women suffer severe cognitive fog, joint pain, and psychological distress without any medical support, often being misdiagnosed with early-onset dementia or clinical depression.', '["Medical Misogyny", "Research Gap", "Women''s Health"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.tracks (key, title, desc_text, meta_text, stats, tax, display_order) VALUES ('industry', 'Industry 4.0: Automation', 'Smarter industrial ecosystems where productivity, sustainability, and safety go hand in hand.', 'Focus: Smart Manufacturing & Workplace Dynamics.', '[80, 65, 70, 90, 85]'::jsonb, '[35, 5, 15, 20]'::jsonb, 5) ON CONFLICT (key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('industry-0', 'industry', 'Legacy Machine Skill Gap', 'Factories where high-tech sensors are slapped onto 40-year-old machines that no living engineer knows how to repair without the sensor''s aid.', 'Retiring master technicians are replaced by iPads and dashboards. The tribal knowledge of how a machine sounds or vibrates is lost, replaced entirely by binary sensor readouts.', 'When the sensor network fails or gets hacked, the entire production line freezes. The workforce has been deskilled to the point where manual override and diagnostic repair is impossible.', '["Deskilling", "Tribal Knowledge", "Fragility"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('industry-1', 'industry', 'Rapid Iteration E-Waste', 'The short lifespan of industrial IoT modules which become obsolete faster than the machinery they monitor, creating specialized electronic waste.', 'While a steel lathe might last 50 years, the microchips monitoring it become unsupported by software updates within 5 years. Upgrading requires entirely new physical chipsets.', 'Factories are generating massive new streams of toxic, heavy-metal e-waste simply to maintain basic network connectivity, contradicting the sustainability promises of Industry 4.0.', '["Planned Obsolescence", "E-Waste", "Lifecycle Mismatch"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('industry-2', 'industry', 'The ''Ghost Work'' Exploitation', 'The hidden, vast army of grossly underpaid human workers who manually label and correct the data needed to make industrial AI seem autonomous.', 'AI cannot autonomously recognize corner cases on an assembly line. It relies on thousands of gig-workers in developing nations to draw bounding boxes around images to train the models.', 'The illusion of automation masks a massive new digital sweatshop economy. It drives down global wages and creates a fragile AI infrastructure wholly dependent on cheap, precarious human labor.', '["Digital Sweatshops", "AI Illusion", "Labor Rights"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('industry-3', 'industry', 'Just-in-Time Fragility', 'Hyper-optimized global manufacturing supply chains that completely collapse across industries the moment a single node fails.', 'Decades of MBA-driven efficiency eliminated all warehouse buffering. Components arrive exactly when needed to save storage costs, leaving zero margin for error.', 'A single event (a stuck ship, a local lockdown, a storm) triggers a global cascade. Factories worldwide shut down within days, halting the production of everything from cars to medical devices.', '["Hyper-optimization", "Supply Chain", "Systemic Risk"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('industry-4', 'industry', 'Over-Automation Complexity Collapse', 'Industrial systems engineered with so many interlocking automated safeguards that novel faults cannot be diagnosed by human operators.', 'Safety layers are stacked upon safety layers. When a multi-variable error occurs, the system throws an opaque ''General Failure'' code, shutting down completely to avoid liability.', 'Downtime skyrockets because human engineers must blindly guess which of the 50 subsystems triggered the abort. The complexity of the safety mechanism becomes the primary point of failure.', '["Complexity Theory", "Opaque Systems", "Downtime"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('industry-5', 'industry', 'Sensory Deprivation in Control Rooms', 'Operators isolated in highly sterile, soundproof automated control rooms slowly losing critical situational awareness of the factory floor.', 'Modern plant design removes humans from the noisy, dangerous floor, placing them in distant, quiet rooms staring at screens. They lose the ambient, physical feedback of the machines.', 'Operators fail to notice the subtle rumble of a failing pump or the smell of overheating plastic—cues that screen-based sensors might miss—leading to catastrophic physical explosions or failures.', '["Ergonomics", "Situational Awareness", "HCI"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.tracks (key, title, desc_text, meta_text, stats, tax, display_order) VALUES ('inclusive', 'Inclusive Innovation', 'An inclusive future enabled by equal access, participation, and opportunity.', 'Focus: Equity & Accessibility Design.', '[75, 90, 80, 85, 70]'::jsonb, '[10, 20, 20, 30]'::jsonb, 6) ON CONFLICT (key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('inclusive-0', 'inclusive', 'Cashless Society Exclusion', 'The systematic removal of the unbanked and elderly from daily commerce as urban centers transition to 100% digital payments.', 'Businesses refuse cash to save on handling times and theft risk. However, acquiring a digital wallet requires a fixed address, a smartphone, and reliable internet.', 'Creates immediate, hard barriers to survival for homeless populations, undocumented immigrants, and the elderly. They are effectively exiled from purchasing food or using public transit.', '["Financial Exclusion", "Cashless", "Urban Poverty"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('inclusive-1', 'inclusive', 'Biometric Failures for Darker Skin', 'Pervasive issues where facial recognition access controls and optical heart rate sensors consistently fail to register people with higher melanin levels.', 'Tech hardware and AI models are overwhelmingly tested on lighter-skinned datasets. Infrared sensors for soap dispensers and green-light sensors for smartwatches literally do not reflect well off dark skin.', 'Racial bias encoded into the physical environment. People of color are locked out of secure buildings, denied sanitary facilities, and provided dangerously inaccurate health telemetry by medical devices.', '["Algorithmic Racism", "Hardware Bias", "Biometrics"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('inclusive-2', 'inclusive', 'Nomadic Financial Exclusion', 'The inability for pastoralists or digital nomads to access credit due to lack of a permanent ''fixed'' address for KYC requirements.', 'Global ''Know Your Customer'' (KYC) banking laws are rooted in 19th-century concepts of land ownership. They cannot process individuals whose primary residence shifts seasonally.', 'Millions of legitimate workers are forced into predatory, high-interest shadow banking systems. It prevents wealth generation for indigenous populations and modern gig-workers alike.', '["KYC Laws", "Shadow Banking", "Mobility"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('inclusive-3', 'inclusive', 'Inaccessible Digital Infrastructure', 'The vast majority of essential government and health portals being incompatible with screen readers or keyboard-only navigation.', 'Web development prioritizes aesthetic frameworks (like React/Vue) over semantic HTML. Accessibility is treated as an optional, post-launch compliance checklist rather than a foundational architecture.', 'Disabled citizens are legally disenfranchised. They cannot file taxes, book vaccine appointments, or access social security without relying entirely on a sighted/able-bodied proxy.', '["A11y", "Digital Rights", "Semantic Web"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('inclusive-4', 'inclusive', 'Design for the ''Average'' User', 'Physical ergonomics and UI paradigms that optimize entirely for a mythical ''average'' body and mind, marginalizing outliers.', 'Industrial design relies on ''standardized anthropometric data'' (usually based on mid-20th-century military men) to mass-produce interfaces cheaply.', 'Everything from seatbelts to smartphone keyboards creates micro-frictions or outright physical danger for anyone too short, too tall, left-handed, or neurodivergent, embedding subtle hostility into everyday life.', '["Ergonomics", "Standardization", "Hostile Design"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('inclusive-5', 'inclusive', 'Automated Hiring Filter Exclusion', 'Applicant Tracking Systems (ATS) instantly rejecting candidates whose resumes feature non-traditional formatting, employment gaps, or non-ivy keywords.', 'HR departments rely entirely on crude keyword-matching algorithms to filter thousands of applications, avoiding the labor of actually reading human experience.', 'A massive, artificial talent shortage. Brilliant candidates from diverse backgrounds, non-linear career paths, or self-taught backgrounds are permanently firewalled out of the modern economy.', '["ATS Bias", "HR Tech", "Gatekeeping"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.tracks (key, title, desc_text, meta_text, stats, tax, display_order) VALUES ('resilience', 'Building with Resilience', 'Solutions that help communities anticipate, withstand, and recover from calamities.', 'Focus: Disaster Recovery & Community Strength.', '[85, 75, 60, 95, 90]'::jsonb, '[25, 10, 5, 40]'::jsonb, 7) ON CONFLICT (key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('resilience-0', 'resilience', 'Post-Disaster ''Invisible'' Trauma', 'The psychological collapse of communities 6-12 months after a disaster, long after emergency aid and media attention have vanished.', 'Disaster funding is heavily front-loaded for physical infrastructure (rebuilding roads, dropping food). Mental health intervention is treated as a luxury and defunded once the cameras leave.', 'A secondary crisis of substance abuse, domestic violence, and suicide ravages the surviving community. The societal fabric collapses just as the physical buildings are restored.', '["Mental Health", "Aid Lifecycle", "Secondary Crisis"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('resilience-1', 'resilience', 'Supply Chain Hoarding Cascades', 'Rapid panic buying triggered by unverified social media rumors that instantly drains retail stocks, fabricating actual resource shortages.', 'Algorithmic social platforms amplify panic and fear to drive engagement. A single viral post about a potential shortage creates a self-fulfilling stampede on the physical supply chain.', 'Vulnerable populations (like the elderly or poor who cannot afford to buy in bulk) are instantly deprived of essential goods like baby formula or medicine, manufactured entirely by digital hysteria.', '["Social Contagion", "Supply Shock", "Misinformation"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('resilience-2', 'resilience', 'Climate Gentrification', 'Wealthy coastal populations retreating to higher, safer ground, subsequently pricing out the lower-income communities already living there.', 'As sea levels rise and insurance companies alter risk models, previously undesirable inland or elevated urban areas suddenly become highly valuable ''safe zones'' for developers.', 'Legacy, low-income communities are economically evicted from their historical homes and forced out toward the high-risk flood plains or fire zones the wealthy just abandoned.', '["Gentrification", "Climate Migration", "Housing Equity"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('resilience-3', 'resilience', 'Insurance Retreat from High-Risk Zones', 'Major insurance companies abruptly pulling coverage from entire states prone to wildfires and hurricanes, leaving homeowners financially ruined.', 'Actuarial models show that extreme weather events are no longer anomalies but baselines. The financial risk of insuring certain geographies (e.g., California, Florida) mathematically breaks the insurance business model.', 'The complete collapse of local real estate markets. Mortgages default as homes become uninsurable, wiping out generational wealth for the middle class and creating vast, unlivable ''uninsured deserts''.', '["Actuarial Science", "Economic Collapse", "Climate Risk"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('resilience-4', 'resilience', 'Cascading Infrastructure Failure', 'The domino effect where a severe storm knocks out a power substation, which stops water pumps, which overheats telecom servers.', 'Modern critical infrastructures are hyper-interdependent but managed by separate, uncoordinated private entities. There is no central ''circuit breaker'' to decouple these systems during a shock.', 'A localized weather event rapidly transforms into a regional dark age. Communications, sanitation, and energy fail simultaneously, rendering standard emergency response protocols utterly useless.', '["Systemic Risk", "Interdependency", "Infrastructure"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
INSERT INTO public.problems (problem_key, track_key, title, detail, context, impact, tags, status) VALUES ('resilience-5', 'resilience', 'Warning Fatigue and Apathy', 'Populations subjected to too many minor alerts or false alarms developing severe psychological apathy, causing them to ignore life-threatening orders.', 'Over-cautious municipalities blanket broadcast mobile alerts for minor storms or distant threats to avoid liability. The alert tone loses its neurological salience.', 'When a truly catastrophic event (like a fast-moving wildfire) occurs, evacuation compliance drops to near zero. Citizens assume it''s ''just another test'', resulting in massive, preventable loss of life.', '["Alert Fatigue", "Human Psychology", "Emergency Comms"]'::jsonb, 'approved') ON CONFLICT (problem_key) DO NOTHING;
